import { useEffect, useState } from 'react';

const GradeStudents = () => {
  const [students, setStudents] = useState([]);
  const [grades, setGrades] = useState([]);
  const [studentId, setStudentId] = useState('');
  const [subject, setSubject] = useState('');
  const [grade, setGrade] = useState('');

  useEffect(() => {
    fetch("http://localhost:3001/users?role=student")
      .then(res => res.json())
      .then(data => setStudents(data));

    fetch("http://localhost:3001/grades")
      .then(res => res.json())
      .then(data => setGrades(data));
  }, []);

  const addGrade = async () => {
    await fetch("http://localhost:3001/grades", {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ studentId: parseInt(studentId), subject, grade }),
    });
    window.location.reload();
  };

  return (
    <div>
      <h2>Оценки</h2>
      <select value={studentId} onChange={e => setStudentId(e.target.value)}>
        <option>Выберите ученика</option>
        {students.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
      </select>
      <input placeholder="Предмет" value={subject} onChange={e => setSubject(e.target.value)} />
      <input placeholder="Оценка" value={grade} onChange={e => setGrade(e.target.value)} />
      <button onClick={addGrade}>Добавить</button>
    </div>
  );
};

export default GradeStudents;
